// https://developer.mozilla.org/en-US/docs/Web/HTTP/Status
const defaultFailureStatusCodes = [408, 409, 425, 429, 500, 502, 503, 504];

export const CIRCUIT_BREAKER_REGISTRY: unique symbol = Symbol(
  "ofetchCircuitBreakerRegistry"
);

export type CircuitState = "closed" | "open" | "half-open";

export interface CircuitBreakerEntry {
  state: CircuitState;
  failures: number;
  nextAttempt: number;
  halfOpenInFlight: number;
}

export interface ResolvedCircuitBreakerConfig {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

export type CircuitBreakerRegistry = Map<string, CircuitBreakerEntry>;

export function createCircuitBreakerRegistry(): CircuitBreakerRegistry {
  return new Map();
}

export function resolveCircuitBreakerConfig(
  option: true | CircuitBreakerOptions
): ResolvedCircuitBreakerConfig {
  if (option === true) {
    return {
      threshold: 5,
      cooldown: 30_000,
      halfOpenMaxRequests: 1,
      failureStatusCodes: defaultFailureStatusCodes,
    };
  }
  return {
    threshold: option.threshold ?? 5,
    cooldown: option.cooldown ?? 30_000,
    halfOpenMaxRequests: option.halfOpenMaxRequests ?? 1,
    failureStatusCodes: option.failureStatusCodes ?? defaultFailureStatusCodes,
  };
}

export function resolveCircuitOrigin(
  request: FetchRequest,
  baseURL?: string
): string {
  if (typeof Request !== "undefined" && request instanceof Request) {
    return new URL(request.url).origin;
  }
  if (request instanceof URL) {
    return request.origin;
  }
  try {
    return new URL(String(request), baseURL).origin;
  } catch {
    return String(request);
  }
}

export function getCircuitBreakerEntry(
  registry: CircuitBreakerRegistry,
  origin: string
): CircuitBreakerEntry {
  let entry = registry.get(origin);
  if (!entry) {
    entry = { state: "closed", failures: 0, nextAttempt: 0, halfOpenInFlight: 0 };
    registry.set(origin, entry);
  }
  return entry;
}

export interface CircuitBreakerDecision {
  allowed: boolean;
  isProbe: boolean;
}

export function evaluateCircuitBreaker(
  entry: CircuitBreakerEntry,
  config: ResolvedCircuitBreakerConfig,
  now: number
): CircuitBreakerDecision {
  if (entry.state === "open") {
    if (now >= entry.nextAttempt) {
      entry.state = "half-open";
      entry.halfOpenInFlight = 0;
    } else {
      return { allowed: false, isProbe: false };
    }
  }

  if (entry.state === "half-open") {
    if (entry.halfOpenInFlight >= config.halfOpenMaxRequests) {
      return { allowed: false, isProbe: false };
    }
    entry.halfOpenInFlight++;
    return { allowed: true, isProbe: true };
  }

  return { allowed: true, isProbe: false };
}

export function recordCircuitBreakerSuccess(entry: CircuitBreakerEntry): void {
  entry.failures = 0;
  if (entry.state === "half-open") {
    entry.state = "closed";
  }
}

export function recordCircuitBreakerFailure(
  entry: CircuitBreakerEntry,
  config: ResolvedCircuitBreakerConfig,
  now: number
): void {
  entry.failures++;
  if (entry.state === "half-open") {
    entry.state = "open";
    entry.nextAttempt = now + config.cooldown;
  } else if (entry.state === "closed" && entry.failures >= config.threshold) {
    entry.state = "open";
    entry.nextAttempt = now + config.cooldown;
  }
}

export function releaseCircuitBreakerSlot(entry: CircuitBreakerEntry): void {
  if (entry.halfOpenInFlight > 0) {
    entry.halfOpenInFlight--;
  }
}
